127	    const priority: SnapMode[] = [
128	      'endpoint',
129	      'midpoint',
130	      'intersection',
131	      'perpendicular',
132	      'parallel',
133	      'tangent',
134	      'nearest',
135	      'grid',
136	      'polar',
137	    ];
138	    for (const mode of priority) {
139	      if (!this.modes[mode]) continue;
140	      const hit = candidates.find((c) => c.mode === mode);
141	      if (hit) return hit;
