234	    initial: PlanCameraSnapshot,
235	    levelOrder: string[],
236	    config: Partial<PlanCameraConfig> = {},
237	  ) {
238	    this.snapshotState = { ...initial, centerMm: { ...initial.centerMm } };
239	    this.config = { ...CAMERA_DEFAULTS, ...config };
240	    this.levelOrder = [...levelOrder];
241	  }
242	
243	  snapshot(): PlanCameraSnapshot {
244	    return {
245	      plotScale: this.snapshotState.plotScale,
246	      centerMm: { ...this.snapshotState.centerMm },
247	      activeLevelId: this.snapshotState.activeLevelId,
248	    };
249	  }
250	
251	  /** Wheel zoom; positive `delta` zooms out (numerator increases). */
252	  wheelZoom(delta: number, anchorMm?: { xMm: number; yMm: number }): void {
253	    const { minScale, maxScale } = this.config;
254	    const factor = delta > 0 ? 1.15 : 1 / 1.15;
255	    const next = clamp(this.snapshotState.plotScale * factor, minScale, maxScale);
256	    if (anchorMm) {
257	      // Anchor zoom: shift center toward anchor proportional to scale change.
258	      const ratio = 1 - this.snapshotState.plotScale / next;
259	      this.snapshotState.centerMm = {
260	        xMm:
261	          this.snapshotState.centerMm.xMm +
262	          (anchorMm.xMm - this.snapshotState.centerMm.xMm) * ratio,
263	        yMm:
264	          this.snapshotState.centerMm.yMm +
265	          (anchorMm.yMm - this.snapshotState.centerMm.yMm) * ratio,
266	      };
267	    }
268	    this.snapshotState.plotScale = next;
269	  }
270	
271	  /** Pan by world-mm delta. */
272	  panMm(dxMm: number, dyMm: number): void {
273	    this.snapshotState.centerMm = {
274	      xMm: this.snapshotState.centerMm.xMm + dxMm,
275	      yMm: this.snapshotState.centerMm.yMm + dyMm,
276	    };
277	  }
278	
279	  /** Zoom-to-fit a bbox; `padding` in mm. */
280	  fit(
281	    bbox: { minMm: { xMm: number; yMm: number }; maxMm: { xMm: number; yMm: number } },
282	    padding = 1000,
283	  ): void {
284	    const cx = (bbox.minMm.xMm + bbox.maxMm.xMm) / 2;
285	    const cy = (bbox.minMm.yMm + bbox.maxMm.yMm) / 2;
286	    const span = Math.max(bbox.maxMm.xMm - bbox.minMm.xMm, bbox.maxMm.yMm - bbox.minMm.yMm, 1);
287	    const proposed = (span + padding * 2) / 100; // span 10 m → ~1:100
288	    this.snapshotState.centerMm = { xMm: cx, yMm: cy };
289	    this.snapshotState.plotScale = clamp(proposed, this.config.minScale, this.config.maxScale);
290	  }
291	
292	  /** PageUp / PageDown level cycling per §14.6. */
293	  cycleLevel(direction: 'up' | 'down'): string {
294	    const idx = this.levelOrder.indexOf(this.snapshotState.activeLevelId);
295	    if (idx < 0) return this.snapshotState.activeLevelId;
296	    const delta = direction === 'down' ? 1 : -1;
297	    const nextIdx = (idx + delta + this.levelOrder.length) % this.levelOrder.length;
298	    const nextId = this.levelOrder[nextIdx]!;
299	    this.snapshotState.activeLevelId = nextId;
300	    return nextId;
301	  }
302	
303	  /** Empty-state copy per §14.7. */
304	  emptyStateMessage(): { headline: string; hint: string } {
305	    return {
306	      headline: 'This level is empty.',
307	      hint: 'Press W to draw a wall, or insert the seed house from the Project menu.',
308	    };
309	  }
310	}
