75	  const stepMm = halfWorldM < 5 ? 250 : halfWorldM < 12 ? 500 : halfWorldM < 24 ? 1000 : 2000;
76	  const snapMm = Math.max(stepMm * 3, 300);
77	  return { stepMm, snapMm };
