80	function rayToPlanMm(
81	  renderer: THREE.WebGLRenderer,
82	  camera: THREE.Camera,
83	  clientX: number,
84	  clientY: number,
85	) {
86	  const rect = renderer.domElement.getBoundingClientRect();
87	  const ndc = new THREE.Vector2(
88	    ((clientX - rect.left) / rect.width) * 2 - 1,
89	    -(((clientY - rect.top) / rect.height) * 2 - 1),
90	  );
91	  const raycaster = new THREE.Raycaster();
92	  raycaster.setFromCamera(ndc, camera);
93	  const plane = new THREE.Plane(new THREE.Vector3(0, 1, 0), -SLICE_Y);
94	  const pt = new THREE.Vector3();
95	  if (!raycaster.ray.intersectPlane(plane, pt)) return null;
96	  return { xMm: pt.x * 1000, yMm: pt.z * 1000 };
97	}
