106	function nearestWallAt(
107	  elementsById: Record<string, Element>,
108	  activeLevelId: string | undefined,
109	  xMm: number,
110	  yMm: number,
111	): { wall: Extract<Element, { kind: 'wall' }>; alongT: number; distMm: number } | undefined {
112	  const px = xMm / 1000;
113	  const pz = yMm / 1000;
114	  let best:
115	    | { wall: Extract<Element, { kind: 'wall' }>; alongT: number; distMm: number }
116	    | undefined;
117	  for (const el of Object.values(elementsById)) {
118	    if (el.kind !== 'wall') continue;
119	    if (activeLevelId && el.levelId !== activeLevelId) continue;
120	    const ax = el.start.xMm / 1000;
121	    const az = el.start.yMm / 1000;
122	    const bx = el.end.xMm / 1000;
123	    const bz = el.end.yMm / 1000;
124	    const abx = bx - ax;
125	    const abz = bz - az;
126	    const len2 = abx * abx + abz * abz;
127	    const rawT = Math.max(
128	      0,
129	      Math.min(1, ((px - ax) * abx + (pz - az) * abz) / Math.max(len2, 1e-9)),
130	    );
131	    const fx = ax + abx * rawT;
132	    const fz = az + abz * rawT;
133	    const distMm = Math.hypot((px - fx) * 1000, (pz - fz) * 1000);
134	    if (!best || distMm < best.distMm) best = { wall: el, alongT: rawT, distMm };
135	  }
136	  return best;
137	}
