142	    ? `Axis ${Math.floor(Math.abs((syMm + 5000) / 3800)) + 1}`
143	    : String.fromCharCode(66 + Math.min(10, Math.floor(Math.abs(exMm - sxMm + 8200) / 4200)));
144	}
